PROMPT_3211 = PROMPT_3211.replace("${FARMAK_BASE_CONTEXT}", FARMAK_BASE_CONTEXT)
PROMPT_3212 = PROMPT_3212.replace("${FARMAK_BASE_CONTEXT}", FARMAK_BASE_CONTEXT)
PROMPT_DELTA = PROMPT_DELTA.replace("${FARMAK_BASE_CONTEXT}", FARMAK_BASE_CONTEXT)


def build_farmak_prompt(subprocess: str, mode: str, role: str) -> str:
    """Порт JS buildFarmakPrompt(subprocess, mode, role)."""
    role = role or ""
    if subprocess == "3211":
        base_prompt = PROMPT_3211
    elif mode == "both":
        base_prompt = PROMPT_DELTA
    else:
        base_prompt = PROMPT_3212

    role_ctx = ""
    if "Дизайнер" in role:
        role_ctx = "\nУЧАСНИК — ДИЗАЙНЕР: знає технічні деталі ARIS і BPMN. Питай детально про кроки, нотацію, технічні діаграми, доступи в систему."
    elif "L4" in role or "L3" in role:
        role_ctx = "\nУЧАСНИК — ВЛАСНИК ПРОЦЕСУ: знає операційний рівень. Фокус на кроках, відповідальності, реальних проблемах і термінах."
    elif "Експерт" in role:
        role_ctx = "\nУЧАСНИК — ЕКСПЕРТ: знає предметну область. Питай про суть процесу, типові проблеми, ризики, потенціал покращення."
    elif "аналітик" in role:
        role_ctx = "\nУЧАСНИК — ПРОЦЕСНИЙ АНАЛІТИК: знає методологію. Можна використовувати технічні терміни BPM, RACI, BPMN."

    mode_ctx = ""
    if mode == "asis" and subprocess != "3211":
        mode_ctx = "\nРЕЖИМ AS-IS: Описуємо процес як він є ЗАРАЗ. Не проектуємо — фіксуємо реальність, включно з проблемами."
    elif mode == "tobe" and subprocess != "3211":
        mode_ctx = "\nРЕЖИМ TO-BE: Проектуємо ЦІЛЬОВИЙ процес. Питай чому саме так і яке обґрунтування кожного рішення."

    return base_prompt + role_ctx + mode_ctx


def build_interview_system(meta: dict) -> str:
    """
    Збирає системний промпт інтерв'ю на основі метаданих сесії.
    Дзеркалить логіку startSession() з фронтенду, але промпти беруться з бекенду.
    """
    meta = meta or {}
    name = (meta.get("name") or "").strip()
    dtype = meta.get("docType") or "process"
    dtype_name = meta.get("dtypeName") or ""
    uploaded = meta.get("uploadedText") or ""

    if dtype == "farmak_bpm":
        sub_code = meta.get("subCode") or "3212"
        mode_code = meta.get("modeCode") or "tobe"
        role = meta.get("farmakRole") or ""
        sys_prompt = build_farmak_prompt(sub_code, mode_code, role)
        ctx = f'Тема сесії: "{name}"\nТип документу: {dtype_name}\n'
        ctx += f"Роль учасника: {role}\n"
        ctx += f"Підпроцес: {meta.get('farmakSubprocess','')}\n"
        ctx += f"Режим моделювання: {meta.get('farmakMode','')}\n\n"
    else:
        sys_prompt = PROMPTS_BY_TYPE.get(dtype) or PROMPTS_BY_TYPE["process"]
        ctx = f'Тема сесії: "{name}"\nТип документу: {dtype_name}\n'

    ctx += (f"\nНаданий документ/шаблон:\n{uploaded}\n" if uploaded else "") + f"\n{sys_prompt}"
    return ctx


def build_struct_prompt(transcript: str) -> str:
    return STRUCT_PROMPT.replace("${transcript}", transcript or "")


def build_doc_prompt(transcript: str, doc_label: str, name: str) -> str:
    return (DOC_PROMPT
            .replace("${docLabel}", doc_label or "Документ")
            .replace("${name}", name or "")
            .replace("${transcript}", transcript or ""))


def build_gen_prompt(transcript: str, name: str) -> str:
    return (GEN_PROMPT
            .replace("${name}", name or "")
            .replace("${transcript}", transcript or ""))


def build_diag_prompt(transcript: str, name: str) -> str:
    return (DIAG_PROMPT
            .replace("${name}", name or "")
            .replace("${transcript}", transcript or ""))

